context:
/* sanity check */
if (size <= sizeof(fwupd_guid_t)) {
	g_set_error(error,
		    FWUPD_ERROR,
		    FWUPD_ERROR_INVALID_DATA,
		    "SignatureSize invalid: 0x%x",
		    (guint)size);
	return FALSE;
}

if (tmp != NULL) {
	priv->kind = fu_efi_signature_kind_from_string(tmp);
	if (priv->kind == FU_EFI_SIGNATURE_KIND_UNKNOWN) {
		g_set_error(error,
			    FWUPD_ERROR,
			    FWUPD_ERROR_INVALID_DATA,
			    "invalid kind: %s",
			    tmp);
		return FALSE;
	}
}

/* catch the strtab */
if (i == fu_struct_elf_file_header64le_get_shstrndx(st_fhdr)) {
	if (fu_struct_elf_section_header64le_get_type(st_shdr) !=
	    FU_ELF_SECTION_HEADER_TYPE_STRTAB) {
		g_set_error(
		    error,
		    FWUPD_ERROR,
		    FWUPD_ERROR_INVALID_DATA,
		    "shstrndx section type was not strtab, was %s",
		    fu_elf_section_header_type_to_string(
			fu_struct_elf_section_header64le_get_type(st_shdr)));
		return FALSE;
	}

for (guint i = 0; i < imgs->len; i++) {
	FuFirmware *img = g_ptr_array_index(imgs, i);
	if (fu_firmware_get_id(img) == NULL) {
		g_set_error(error,
			    FWUPD_ERROR,
			    FWUPD_ERROR_INVALID_DATA,
			    "section 0x%x must have an ID",
			    (guint)fu_firmware_get_idx(img));
		return NULL;
	}
	fu_elf_firmware_strtab_insert(strtab, fu_firmware_get_id(img));
}

/* GUID */
if (!fu_input_stream_read_safe(stream,
			       (guint8 *)&guid,
			       sizeof(guid),
			       0x0, /* seek to */
			       0x0, /* offset */
			       sizeof(guid),
			       error)) {
	g_prefix_error_literal(error, "failed to read signature GUID: ");
	return FALSE;
}

if (!fu_efivars_get_data(self,
			 FU_EFIVARS_GUID_EFI_GLOBAL,
			 "BootNext",
			 &buf,
			 &bufsz,
			 NULL,
			 error))
	return FALSE;
if (bufsz != sizeof(guint16)) {
	g_set_error_literal(error, FWUPD_ERROR, FWUPD_ERROR_INVALID_DATA, "invalid size");
	return FALSE;
}
